# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControl:
    def __init__(self):
        self.db = sqlite3.connect('permissions.db')
        self.cursor = self.db.cursor()
        self.create_table()

    def create_table(self):
        self.cursor.execute('''CREATE TABLE IF NOT EXISTS users (
                                id INTEGER PRIMARY KEY,
                                username TEXT UNIQUE,
                                password TEXT,
                                access_level INTEGER)''')

    def add_user(self, username, password, access_level):
        self.cursor.execute("INSERT INTO users (username, password, access_level) VALUES (?, ?, ?)", (username, password, access_level))
        self.db.commit()

    def check_permissions(self, username, file_name, min_access_level):
        self.cursor.execute("SELECT access_level FROM users WHERE username=? AND access_level>=?", (username, min_access_level))
        result = self.cursor.fetchone()
        return bool(result)

    def open_file(self, username, file_name):
        if self.check_permissions(username, file_name, 1):
            try:
                with open(file_name, 'r') as f:
                    return f.read()
            except FileNotFoundError:
                return None
        else:
            return None

    def close(self):
        self.db.close()

# Example usage
fac = FileAccessControl()
fac.add_user('john', 'password123', 2) # User john with access level 2
content = fac.open_file('john', 'example.txt') # Check permission and open example.txt if john has access level >= 1
fac.close()